-- 003_seed_geo_country_admin_structure_all_countries.sql
-- Purpose:
--   Fill geo.country_admin_structure for EVERY country present in geo.country.
--   Level 1 uses ISO 3166-2 subdivision type information when available.
--   Levels 2 and 3 are generic global fallbacks for UI forms and must be refined country-by-country when exact admin data is imported.
--
-- Main sources:
--   ISO 3166 / ISO 3166-2: principal administrative divisions of countries.
--   GeoNames feature codes: ADM1, ADM2, ADM3 generic administrative levels.
--
-- Important:
--   This script is non-destructive. It uses ON CONFLICT (country_id, admin_level) DO UPDATE.
--   It does NOT fill geo.admin_unit values. It only tells the frontend which location fields can be displayed.

CREATE EXTENSION IF NOT EXISTS pgcrypto;

CREATE SCHEMA IF NOT EXISTS geo;

CREATE TABLE IF NOT EXISTS geo.country_admin_structure (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    country_id UUID NOT NULL REFERENCES geo.country(id),
    admin_level INTEGER NOT NULL,
    unit_type TEXT NOT NULL,
    label_fr TEXT NOT NULL,
    label_en TEXT,
    label_ar TEXT,
    required BOOLEAN NOT NULL DEFAULT false,
    active BOOLEAN NOT NULL DEFAULT true,
    sort_order INTEGER NOT NULL DEFAULT 0,
    metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    CONSTRAINT ux_country_admin_structure_level UNIQUE (country_id, admin_level)
);

CREATE INDEX IF NOT EXISTS ix_country_admin_structure_country
ON geo.country_admin_structure(country_id);

CREATE INDEX IF NOT EXISTS ix_country_admin_structure_country_active
ON geo.country_admin_structure(country_id, active, sort_order);

