INSERT INTO geo.country_admin_structure (
    country_id, admin_level, unit_type, label_fr, label_en, label_ar,
    required, active, sort_order, metadata_json
)
SELECT
    c.id,
    o.admin_level,
    o.unit_type,
    o.label_fr,
    o.label_en,
    o.label_ar,
    o.required,
    o.active,
    o.sort_order,
    o.metadata_json
FROM overrides o
JOIN geo.country c ON c.iso2 = o.iso2
ON CONFLICT (country_id, admin_level) DO UPDATE SET
    unit_type = EXCLUDED.unit_type,
    label_fr = EXCLUDED.label_fr,
    label_en = EXCLUDED.label_en,
    label_ar = EXCLUDED.label_ar,
    required = EXCLUDED.required,
    active = EXCLUDED.active,
    sort_order = EXCLUDED.sort_order,
    metadata_json = EXCLUDED.metadata_json,
    updated_at = now();

